import { Plus, ChevronLeft, ChevronRight } from 'lucide-react';
import { useCalendarData } from '../hooks/useCalendarData';
import type { CalendarRecord, RecordTag, SpecialRecord } from '../types';

interface CalendarProps {
  onOpenModal: (date: Date | null, recordToEdit?: {record: CalendarRecord, dateStr: string}) => void;
  records: CalendarRecord[];
  tags: RecordTag[];
  onUpdateRecord: (record: CalendarRecord) => void;
}

export function Calendar({ onOpenModal, records, tags, onUpdateRecord }: CalendarProps) {
  const { currentMonth, weeks, nextMonth, prevMonth } = useCalendarData();

  if (weeks.length === 0) {
    return (
      <div className="flex items-center justify-center h-screen bg-gray-50 dark:bg-gray-950 font-sans">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
        </div>
      </div>
    );
  }

  const yearString = currentMonth.getFullYear() + '年';
  const monthString = (currentMonth.getMonth() + 1) + '月';

  const getRecordTagsString = (record: SpecialRecord) => {
    if (!record.tagIds || record.tagIds.length === 0) return 'Unknown Tag';
    return tags.filter(t => record.tagIds.includes(t.id)).map(t => t.name).join(', ');
  };

  return (
    <div className="relative w-full h-screen flex flex-col bg-gray-50 dark:bg-gray-950 font-sans overflow-hidden">

      {/* Floating Add Button */}
      <button 
        onClick={() => onOpenModal(new Date())}
        className="absolute top-6 left-6 z-40 bg-gradient-to-tr from-blue-600 to-indigo-500 hover:from-blue-500 hover:to-indigo-400 text-white p-4 rounded-2xl shadow-xl hover:shadow-2xl shadow-blue-500/30 hover:-translate-y-1 transition-all group border border-white/10"
      >
        <Plus size={28} className="group-hover:rotate-90 transition-transform duration-500" />
      </button>

      {/* Header: Year/Month Navigation */}
      <div className="shrink-0 flex items-center justify-center gap-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-xl border-b border-gray-200/50 dark:border-gray-800/50 px-6 py-4 shadow-sm z-30 min-h-[72px]">
        <button 
          onClick={prevMonth}
          className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors text-gray-600 dark:text-gray-300"
        >
          <ChevronLeft size={24} />
        </button>
        <h2 className="text-xl md:text-2xl font-bold tracking-wider text-gray-800 dark:text-gray-100 min-w-[150px] text-center">
          {yearString} {monthString}
        </h2>
        <button 
          onClick={nextMonth}
          className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors text-gray-600 dark:text-gray-300"
        >
          <ChevronRight size={24} />
        </button>
      </div>

      {/* Grid Scroll Area container */}
      <div className="flex-1 flex flex-col overflow-y-auto w-full max-w-7xl mx-auto items-center px-4 sm:px-6">

        {/* Weekdays Header */}
        <div className="shrink-0 w-full py-3 z-30">
          <div className="grid grid-cols-7 gap-1 sm:gap-2 w-full">
            {['周日', '周一', '周二', '周三', '周四', '周五', '周六'].map(d => (
              <div key={d} className="text-center text-xs font-bold text-gray-400 tracking-widest">
                {d}
              </div>
            ))}
          </div>
        </div>

        {/* Grid Area */}
        <div className="flex-1 w-full pb-8 flex flex-col gap-1 sm:gap-2">
          {weeks.map((week, wIdx) => (
            <div key={wIdx} className="grid grid-cols-7 gap-1 sm:gap-2 flex-1 min-h-[100px]">
              {week.map((cell, cIdx) => {
                if (!cell.date) {
                  return <div key={cIdx} className="bg-transparent rounded-xl" />;
                }

                const dateStr = `${cell.date.getFullYear()}-${String(cell.date.getMonth() + 1).padStart(2, '0')}-${String(cell.date.getDate()).padStart(2, '0')}`;

                const dateRecords = records.filter(r => {
                  if (r.type === 'daily') return true;
                  return r.dateStr === dateStr;
                });

                const dailyRecords = dateRecords.filter(r => r.type === 'daily').sort((a, b) => a.createdAt - b.createdAt);
                const specialRecords = dateRecords.filter(r => r.type === 'special');

                return (
                  <div
                    key={cIdx}
                    onClick={() => onOpenModal(cell.date)}
                    className={`group relative rounded-xl border flex flex-col transition-all duration-200 ease-out cursor-pointer
                      ${cell.isToday 
                        ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800 shadow-sm' 
                        : 'bg-white dark:bg-gray-900 border-gray-200/60 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800/50'}
                      hover:scale-105 hover:z-20 hover:shadow-lg active:scale-95 hover:ring-2 ring-blue-400 ring-offset-2 dark:ring-offset-gray-950 outline-none overflow-visible min-h-[100px] h-auto`}
                  >
                    <div className="flex justify-between items-start w-full p-2 pb-1 shrink-0">
                      <span className={`text-[10px] sm:text-xs font-bold leading-none
                        ${cell.isToday ? 'text-blue-600 dark:text-blue-400' : 'text-gray-500 dark:text-gray-400 group-hover:text-gray-900 dark:group-hover:text-gray-100'}`}>
                        {cell.label}
                      </span>
                    </div>

                    {/* Habits Area */}
                    <div className="habit-container flex flex-wrap gap-1 p-1 min-h-[28px]">
                      {dailyRecords.map(record => {
                        const isCompleted = record.completedDates.includes(dateStr);
                        const firstChar = (record as any).content?.charAt(0) || '?';
                        return (
                          <div
                            key={`habit-${record.id}`}
                            title={(record as any).content}
                            onClick={(e) => {
                              e.stopPropagation();
                              onUpdateRecord({
                                ...record,
                                completedDates: isCompleted 
                                  ? record.completedDates.filter(d => d !== dateStr) 
                                  : [...record.completedDates, dateStr]
                              });
                            }}
                            className={`w-5 h-5 rounded-md transition-all duration-200 shrink-0 flex items-center justify-center text-[10px] font-bold select-none hover:scale-110 active:scale-90
                              ${isCompleted 
                                ? 'shadow-sm border-2 border-solid border-black/10 dark:border-white/10' 
                                : 'bg-gray-100 dark:bg-gray-800 border-2 border-dashed border-gray-300 dark:border-gray-700 text-gray-400'}
                            `}
                            style={isCompleted ? { backgroundColor: record.color.bg, color: record.color.text } : {}}
                          >
                            {firstChar}
                          </div>
                        );
                      })}
                    </div>

                    {/* Divider */}
                    <div className="border-t border-gray-100 dark:border-gray-800 mx-1" />

                    {/* Events Area */}
                    <div className="event-container flex flex-col gap-1 p-1 flex-1">
                      {specialRecords.map(record => {
                        const tagsStr = getRecordTagsString(record as SpecialRecord);
                        return (
                          <div
                            key={`special-${record.id}`}
                            onClick={(e) => {
                              e.stopPropagation();
                              onOpenModal(cell.date, { record, dateStr });
                            }}
                            className="text-[9px] sm:text-[10px] px-1.5 py-1 rounded shadow-sm text-left truncate font-medium w-full hover:brightness-95 transition-all"
                            style={{ backgroundColor: record.color.bg, color: record.color.text }}
                          >
                            {tagsStr}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

