/* eslint-disable react-hooks/set-state-in-effect */
import { useState, useEffect } from 'react';
import { X, Plus, Check, Trash2 } from 'lucide-react';
import { presetColors } from '../utils/colors';
import type { CalendarColor } from '../utils/colors';
import type { CalendarRecord, RecordTag, DailyRecord } from '../types';

interface RecordModalProps {
  isOpen: boolean;
  onClose: () => void;
  selectedDate: Date | null;
  onAddRecord: (record: CalendarRecord) => void;
  onUpdateRecord: (record: CalendarRecord) => void;
  onDeleteRecord: (id: string, type: 'daily' | 'special', content?: string) => void;
  editingRecord: {record: CalendarRecord, dateStr: string} | null;
  tags: RecordTag[];
  onAddTag: (tag: RecordTag) => void;
  records: CalendarRecord[];
}

export function RecordModal({ isOpen, onClose, selectedDate, onAddRecord, onUpdateRecord, onDeleteRecord, editingRecord, tags, onAddTag, records }: RecordModalProps) {
  const [activeTab, setActiveTab] = useState<'daily' | 'special'>('daily');

  // Daily Record State
  const [dailyContent, setDailyContent] = useState('');
  const [selectedColor, setSelectedColor] = useState<CalendarColor>(presetColors[0]);

  // Special Record State
  const [selYear, setSelYear] = useState(new Date().getFullYear());
  const [selMonth, setSelMonth] = useState(new Date().getMonth() + 1);
  const [selDay, setSelDay] = useState(new Date().getDate());
  const [selectedTagIds, setSelectedTagIds] = useState<string[]>([]);
  const [specialColor, setSpecialColor] = useState<CalendarColor>(presetColors[0]);
  const [dateError, setDateError] = useState('');

  // New Tag State
  const [isAddingTag, setIsAddingTag] = useState(false);
  const [newTagName, setNewTagName] = useState('');

  // Reset states when modal opens
  // eslint-disable-next-line react-hooks/set-state-in-effect
  useEffect(() => {
    if (isOpen) {
      if (editingRecord) {
        if (editingRecord.record.type === 'daily') {
          setActiveTab('daily');
          setDailyContent(editingRecord.record.content);
          setSelectedColor(editingRecord.record.color);
        } else {
          setActiveTab('special');
          const [y, m, d] = editingRecord.record.dateStr.split('-').map(Number);
          setSelYear(y);
          setSelMonth(m);
          setSelDay(d);
          setSelectedTagIds(editingRecord.record.tagIds || []);
          setSpecialColor(editingRecord.record.color);
        }
      } else {
        setDailyContent('');
        setSelectedColor(presetColors[0]);
        setDateError('');

        if (selectedDate) {
          setSelYear(selectedDate.getFullYear());
          setSelMonth(selectedDate.getMonth() + 1);
          setSelDay(selectedDate.getDate());
        }

        if (tags.length > 0) {
          setSelectedTagIds([tags[0].id]);
        }
        setSpecialColor(presetColors[10]); 
      }
      setIsAddingTag(false);
      setNewTagName('');
    }
  }, [isOpen, selectedDate, tags, editingRecord]);

  if (!isOpen) return null;

  const targetDateObj = editingRecord && editingRecord.record.type === 'daily' && editingRecord.dateStr 
    ? new Date(editingRecord.dateStr) 
    : selectedDate;
  const dateStrForHeader = targetDateObj ? targetDateObj.toLocaleDateString('zh-CN', { year: 'numeric', month: 'long', day: 'numeric', weekday: 'long' }) : '未选择日期';

  const isValidDate = (year: number, month: number, day: number) => {
    const d = new Date(year, month - 1, day);
    return d.getFullYear() === year && d.getMonth() === month - 1 && d.getDate() === day;
  };

  const currentYears = Array.from({ length: 151 }, (_, i) => 2000 + i);
  const currentMonths = Array.from({ length: 12 }, (_, i) => i + 1);
  const currentDays = Array.from({ length: 31 }, (_, i) => i + 1);

  const handleSaveDaily = () => {
    if (!dailyContent.trim()) return;

    onAddRecord({
      id: `daily_${Date.now()}`,
      type: 'daily',
      createdAt: Date.now(),
      content: dailyContent.trim(),
      color: selectedColor,
      completedDates: [],
    });
    setDailyContent('');
  };

  const handleSaveSpecial = () => {
    if (!isValidDate(selYear, selMonth, selDay)) {
      setDateError('请输入正确的日期');
      return;
    }
    setDateError('');

    if (selectedTagIds.length === 0) return;

    if (editingRecord && editingRecord.record.type === 'special') {
      onUpdateRecord({
        ...editingRecord.record,
        dateStr: `${selYear}-${String(selMonth).padStart(2, '0')}-${String(selDay).padStart(2, '0')}`,
        tagIds: selectedTagIds,
        color: specialColor,
      });
    } else {
      onAddRecord({
        id: `special_${Date.now()}`,
        type: 'special',
        createdAt: Date.now(),
        dateStr: `${selYear}-${String(selMonth).padStart(2, '0')}-${String(selDay).padStart(2, '0')}`,
        tagIds: selectedTagIds,
        color: specialColor,
      });
    }
    onClose();
  };

  const handleAddNewTag = () => {
    if (newTagName.trim()) {
      const newTag = { id: `tag_${Date.now()}`, name: newTagName.trim() };
      onAddTag(newTag);
      setSelectedTagIds(prev => [...prev, newTag.id]);
      setIsAddingTag(false);
      setNewTagName('');
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={onClose}>
      <div 
        className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-200 flex flex-col max-h-[90vh]"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-gray-700/50 shrink-0">
          <h2 className="text-xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent">
            {editingRecord ? (editingRecord.record.type === 'daily' ? '养成管理' : '编辑特殊事件') : (activeTab === 'daily' ? '添加每日记录' : '添加特殊事件')} - {dateStrForHeader}
          </h2>
          <button 
            onClick={onClose} 
            className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700/50 rounded-full transition-colors text-gray-500"
          >
            <X size={20} />
          </button>
        </div>

        {/* Tabs - Only show when NOT editing */}
        {!editingRecord && (
          <div className="flex border-b border-gray-100 dark:border-gray-700/50 shrink-0">
            <button
              className={`flex-1 py-4 text-sm font-semibold transition-all relative ${
                activeTab === 'daily'
                  ? 'text-blue-600 bg-blue-50/50 dark:bg-blue-900/10'
                  : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'
              }`}
              onClick={() => setActiveTab('daily')}
            >
              每日记录
              {activeTab === 'daily' && (
                <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-600 shadow-[0_0_8px_rgba(37,99,235,0.8)]" />
              )}
            </button>
            <button
              className={`flex-1 py-4 text-sm font-semibold transition-all relative ${
                activeTab === 'special'
                  ? 'text-purple-600 bg-purple-50/50 dark:bg-purple-900/10'
                  : 'text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200'
              }`}
              onClick={() => setActiveTab('special')}
            >
              特殊记录
              {activeTab === 'special' && (
                <div className="absolute bottom-0 left-0 w-full h-0.5 bg-purple-600 shadow-[0_0_8px_rgba(147,51,234,0.8)]" />
              )}
            </button>
          </div>
        )}

        {/* Content */}
        <div className="p-6 bg-gray-50/50 dark:bg-gray-800/50 overflow-y-auto flex-1">
          {activeTab === 'daily' ? (
            <div className="space-y-6 animate-in slide-in-from-left-2 duration-300">
              {editingRecord && editingRecord.record.type === 'daily' ? (
                <div className="text-center py-6">
                  <p className="text-xl font-bold text-gray-800 dark:text-gray-100 mb-2">{editingRecord.record.content}</p>
                  <p className="text-sm text-gray-500 mb-6">习惯完成状态现已支持在日历页点击方块直接切换</p>

                  <div className="mt-8 pt-6 border-t border-gray-200 dark:border-gray-700">
                    <button 
                      onClick={() => {
                        onDeleteRecord(editingRecord.record.id, 'daily', (editingRecord.record as DailyRecord).content);
                        onClose();
                      }}
                      className="w-full py-3.5 bg-transparent border-2 border-red-100 hover:border-red-200 hover:bg-red-50 dark:border-red-900/30 dark:hover:border-red-900/50 dark:hover:bg-red-900/20 text-red-600 dark:text-red-400 rounded-xl font-semibold transition-all active:scale-[0.98]"
                    >
                      从全局彻底删除此习惯
                    </button>
                  </div>
                </div>
              ) : (
                <>
                  <div className="space-y-3">
                    <label className="text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center justify-between">
                      <span>🚀 新增习惯名称</span>
                    </label>
                    <input 
                      type="text"
                      value={dailyContent}
                      onChange={(e) => setDailyContent(e.target.value)}
                      className="w-full p-3.5 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-gray-400"
                      placeholder="例如：早起喝水、阅读 30 分钟..."
                      maxLength={20}
                    />
                  </div>

                  <div className="space-y-3">
                    <label className="text-sm font-medium text-gray-700 dark:text-gray-300">🎨 选择主题色</label>
                    <div className="grid grid-cols-9 gap-2">
                      {presetColors.map((color, i) => (
                        <button
                          key={i}
                          onClick={() => setSelectedColor(color)}
                          style={{ backgroundColor: color.bg }}
                          className={`aspect-square rounded-full border-2 transition-transform flex items-center justify-center ${
                            selectedColor === color ? 'border-blue-500 scale-110 shadow-md' : 'border-transparent hover:scale-110'
                          }`}
                        >
                          {selectedColor === color && <Check size={14} style={{ color: color.text }} />}
                        </button>
                      ))}
                    </div>
                  </div>

                  <button 
                    onClick={handleSaveDaily}
                    disabled={!dailyContent.trim()}
                    className="w-full py-3.5 bg-blue-600 disabled:bg-gray-400 disabled:cursor-not-allowed hover:bg-blue-700 focus:ring-4 focus:ring-blue-500/20 text-white rounded-xl font-semibold shadow-lg shadow-blue-500/20 transition-all active:scale-[0.98] mt-4"
                  >
                    确认创建习惯
                  </button>

                  <div className="mt-10 pt-6 border-t border-gray-100 dark:border-gray-700">
                    <h3 className="text-sm font-bold text-gray-400 uppercase tracking-widest mb-4">管理现有习惯</h3>
                    <div className="space-y-2">
                      {records.filter(r => r.type === 'daily').map(record => (
                        <div 
                          key={record.id} 
                          className="flex items-center justify-between p-3 bg-white dark:bg-gray-900 rounded-xl border border-gray-100 dark:border-gray-800 shadow-sm group"
                        >
                          <div className="flex items-center gap-3">
                            <div 
                              className="w-3 h-3 rounded-full" 
                              style={{ backgroundColor: record.color.bg }}
                            />
                            <span className="font-medium text-gray-700 dark:text-gray-200">{(record as DailyRecord).content}</span>
                          </div>
                          <button 
                            onClick={() => onDeleteRecord(record.id, 'daily', (record as DailyRecord).content)}
                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                            title="从全局删除"
                          >
                            <Trash2 size={18} />
                          </button>
                        </div>
                      ))}
                      {records.filter(r => r.type === 'daily').length === 0 && (
                        <p className="text-center py-4 text-gray-400 text-sm italic">暂无全局记录的习惯</p>
                      )}
                    </div>
                  </div>
                </>
              )}
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-2 duration-300">

              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">📅 选择日期</label>
                <div className="flex gap-2">
                  <select 
                    value={selYear} 
                    onChange={e => setSelYear(Number(e.target.value))}
                    className="flex-1 p-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 outline-none focus:ring-2 focus:ring-purple-500"
                  >
                    {currentYears.map(y => <option key={y} value={y}>{y}年</option>)}
                  </select>
                  <select 
                    value={selMonth} 
                    onChange={e => setSelMonth(Number(e.target.value))}
                    className="flex-1 p-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 outline-none focus:ring-2 focus:ring-purple-500"
                  >
                    {currentMonths.map(m => <option key={m} value={m}>{m}月</option>)}
                  </select>
                  <select 
                    value={selDay} 
                    onChange={e => setSelDay(Number(e.target.value))}
                    className="flex-1 p-3 rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 outline-none focus:ring-2 focus:ring-purple-500"
                  >
                    {currentDays.map(d => <option key={d} value={d}>{d}日</option>)}
                  </select>
                </div>
                {dateError && <p className="text-red-500 text-sm mt-1 animate-in slide-in-from-top-1">{dateError}</p>}
              </div>

              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">🏷️ 跑道标签系统</label>
                <div className="flex flex-wrap gap-2">
                  {tags.map(tag => {
                    const isSelected = selectedTagIds.includes(tag.id);
                    return (
                      <button
                        key={tag.id}
                        onClick={() => setSelectedTagIds(prev => prev.includes(tag.id) ? prev.filter(t => t !== tag.id) : [...prev, tag.id])}
                        className={`px-4 py-2 rounded-full border text-sm transition-all shadow-sm ${
                          isSelected
                            ? 'bg-gray-800 text-white border-gray-800 dark:bg-gray-200 dark:text-gray-900 dark:border-gray-200' 
                            : 'bg-white text-gray-800 border-gray-900 dark:bg-gray-900 dark:text-gray-200 dark:border-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800'
                        }`}
                      >
                        {tag.name}
                      </button>
                    );
                  })}

                  {isAddingTag ? (
                    <div className="flex animate-in fade-in slide-in-from-left-2 items-center gap-1">
                      <input
                        autoFocus
                        type="text"
                        value={newTagName}
                        onChange={e => setNewTagName(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && handleAddNewTag()}
                        className="px-3 py-1.5 rounded-full border border-purple-400 outline-none focus:ring-2 focus:ring-purple-500 text-sm w-28 bg-white dark:bg-gray-900"
                        placeholder="新标签..."
                        maxLength={10}
                      />
                      <button onClick={handleAddNewTag} className="p-1.5 bg-purple-100 text-purple-700 rounded-full hover:bg-purple-200">
                        <Check size={16} />
                      </button>
                      <button onClick={() => setIsAddingTag(false)} className="p-1.5 bg-gray-100 text-gray-500 rounded-full hover:bg-gray-200">
                        <X size={16} />
                      </button>
                    </div>
                  ) : (
                    <button 
                      onClick={() => setIsAddingTag(true)}
                      className="px-4 py-2 rounded-full border border-dashed border-gray-400 dark:border-gray-600 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800/50 flex items-center gap-1 text-sm"
                    >
                      <Plus size={16} /> 新标签
                    </button>
                  )}
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">🎨 点缀颜色</label>
                <div className="grid grid-cols-9 gap-2">
                  {presetColors.map((color, i) => (
                    <button
                      key={i}
                      onClick={() => setSpecialColor(color)}
                      style={{ backgroundColor: color.bg }}
                      className={`aspect-square rounded-full border-2 transition-transform flex items-center justify-center ${
                        specialColor === color ? 'border-purple-500 scale-110 shadow-md' : 'border-transparent hover:scale-110'
                      }`}
                    >
                      {specialColor === color && <Check size={14} style={{ color: color.text }} />}
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex flex-col gap-3 mt-8">
                <button 
                  onClick={handleSaveSpecial}
                  disabled={selectedTagIds.length === 0}
                  className="w-full py-3.5 bg-purple-600 disabled:bg-gray-400 disabled:cursor-not-allowed hover:bg-purple-700 focus:ring-4 focus:ring-purple-500/20 text-white rounded-xl font-semibold shadow-lg shadow-purple-500/20 transition-all active:scale-[0.98]"
                >
                  {editingRecord && editingRecord.record.type === 'special' ? '保存修改' : '保存特殊事件'}
                </button>

                {editingRecord && editingRecord.record.type === 'special' && (
                  <button 
                    onClick={() => {
                      onDeleteRecord(editingRecord.record.id, 'special');
                      onClose();
                    }}
                    className="w-full py-3.5 bg-transparent border-2 border-red-100 hover:border-red-200 hover:bg-red-50 dark:border-red-900/30 dark:hover:border-red-900/50 dark:hover:bg-red-900/20 text-red-600 dark:text-red-400 rounded-xl font-semibold transition-all active:scale-[0.98] mt-2"
                  >
                    删除此记录
                  </button>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
